import { useState, useMemo, useEffect } from "react";
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from "recharts";

const EMBEDDED_B64 = "";

async function decodeData(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  const ds = new DecompressionStream("gzip");
  const w = ds.writable.getWriter(); w.write(bytes); w.close();
  const r = ds.readable.getReader();
  const chunks = [];
  while (true) { const {done,value} = await r.read(); if(done) break; chunks.push(value); }
  const tot = chunks.reduce((a,c)=>a+c.length,0);
  const out = new Uint8Array(tot); let off=0;
  for (const ch of chunks) { out.set(ch,off); off+=ch.length; }
  return JSON.parse(new TextDecoder().decode(out));
}

const CABANG_LIST = [
  "BALIKPAPAN","BANDUNG","BANJARMASIN","BANYUWANGI","BEKASI","BLITAR","BOGOR",
  "BOJONEGORO","CIANJUR","CIKARANG","CILEGON","CIMAHI","CIREBON","DEPOK","GARUT",
  "GRESIK","INDRAMAYU","JEMBER","JEPARA","JOMBANG","KARAWANG","KEDIRI","KENDAL",
  "KUDUS","LAMONGAN","MADIUN","MAGELANG","MALANG","MOJOKERTO","PASURUAN",
  "PROBOLINGGO","PULOGADUNG","PURWAKARTA","PURWOKERTO","SALATIGA","SAMARINDA",
  "SEMARANG","SERANG","SIDOARJO","SOLO","SRAGEN","SUBANG","SUKABUMI","SUMEDANG",
  "SURABAYA","TANGKOT","TANGSEL","TASIKMALAYA","TUBAN","TULUNGAGUNG","UNGARAN","YOGYAKARTA",
  "Leads Lainnya"
];

const BULAN = ["Januari","Februari","Maret","April","Mei","Juni","Juli","Agustus","September","Oktober","November","Desember"];
const TEMP_ORDER = ["Hot","Warm","Cold","Garbage"];
const TEMP_COLORS = { Hot:"#e24b4a", Warm:"#ef9f27", Cold:"#378add", Garbage:"#9ca3af" };
const TEMP_BG    = { Hot:"#fef2f2", Warm:"#fffbeb", Cold:"#eff6ff", Garbage:"#f9fafb" };
const TEMP_FG    = { Hot:"#b91c1c", Warm:"#92400e", Cold:"#1d4ed8", Garbage:"#6b7280" };
const SOURCE_COLORS = {
  "Google Ads":"#4285F4","Iklan Cabang":"#ef9f27","Iklan Meta Pusat":"#7F77DD",
  "Instagram Organik":"#E1306C","Website":"#1D9E75","Lainnya":"#9ca3af"
};

// row = [name, phone, cabang_csv, source, ads_cabang, temp, closing, fu_month, ambil_alih, date]
const pr = a => ({
  n:a[0]||"", p:a[1]||"",
  c:a[2]?a[2].split(","):["SURABAYA"],
  s:a[3]||"Lainnya", ac:a[4]||null,
  t:a[5]||"Garbage", cl:a[6]===1,
  fu:a[7]||null, aa:a[8]===1, d:a[9]||"",
  g:a[10]||""
});

function dlCSV(rows, fname) {
  const H = ["Nama","Nomor WA","Cabang","Sumber","Suhu","Closing","FU Bulan","Ambil Alih","Tanggal"];
  const lines = [H.join(","), ...rows.map(r=>[
    `"${r.n}"`,r.p,r.c.join("|"),r.s,r.t,
    r.cl?"Ya":"Tidak",r.fu||"",r.aa?"Ya":"Tidak",r.d
  ].join(","))];
  const a = document.createElement("a");
  a.href = URL.createObjectURL(new Blob([lines.join("\n")],{type:"text/csv;charset=utf-8;"}));
  a.download = fname; a.click();
}

// ── UI ATOMS ──────────────────────────────────────────────────────────────────
const TT = ({active,payload,label}) => {
  if (!active||!payload?.length) return null;
  return (
    <div style={{background:"#fff",border:"1px solid #f0f0f0",borderRadius:8,padding:"8px 12px",fontSize:12,boxShadow:"0 2px 8px rgba(0,0,0,.08)"}}>
      {label&&<div style={{fontWeight:600,marginBottom:4,color:"#374151"}}>{label}</div>}
      {payload.map((p,i)=>(
        <div key={i} style={{display:"flex",alignItems:"center",gap:6,color:"#374151"}}>
          <span style={{width:8,height:8,borderRadius:2,background:p.color,flexShrink:0}}></span>
          {p.name}: <strong>{typeof p.value==="number"?p.value.toLocaleString():p.value}</strong>
        </div>
      ))}
    </div>
  );
};

