    {(title||extra)&&(
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:subtitle?3:10,flexWrap:"wrap",gap:6}}>
        {title&&<div style={{fontWeight:600,fontSize:13,color:"#111827"}}>{title}</div>}
        {extra}
      </div>
    )}
    {subtitle&&<div style={{fontSize:11,color:"#9ca3af",marginBottom:10}}>{subtitle}</div>}
